import numpy as np
def compute_ndvi(nir_band, red_band):
    return (nir_band - red_band) / (nir_band + red_band + 1e-6)

# Use a simple U‑Net to segment fields and assign health scores

CREATE TABLE fields (
  id SERIAL PRIMARY KEY,
  name TEXT,
  geom GEOMETRY(Polygon, 4326),
  crop_type TEXT,
  planted_date DATE,
  owner TEXT
);
CREATE INDEX idx_fields_geom ON fields USING GIST (geom);

CREATE TABLE field_health (
  time TIMESTAMPTZ,
  field_id INT,
  ndvi_mean FLOAT,
  pest_count INT
);
SELECT create_hypertable('field_health', 'time');

class PrecisionSprayer(Node):
    def __init__(self):
        super().__init__('precision_sprayer')
        self.ndvi_sub = self.create_subscription(Image, '/ndvi_map', self.cb, 10)
        self.spray_pub = self.create_publisher(Float32, '/spray_rate', 10)

    def cb(self, msg):
        ndvi = decode_image(msg)
        if ndvi[center] < 0.3:
            self.spray_pub.publish(Float32(data=1.0))  # full rate
